#include<bits/stdc++.h>
using namespace std;
long long INF=INT_MIN/10;
int main(){
    long long up[2003][2003],down[2003][2003],a[2003][2003],n,m;
    cin>>n>>m;
    for(int i=0;i<=n+1;i++){
        for(int j=0;j<=m+1;j++){
            up[i][j]=INF;
        }
    }
    for(int i=0;i<=n+1;i++){
        for(int j=0;j<=m+1;j++){
            down[i][j]=INF;
        }
    }

    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    up[1][1]=0;
    down[1][1]=0;
    for(int j=1;j<=m;j++){
        for(int i=n;i>=1;i--) down[i][j]=max(down[i][j],max(down[i+1][j],max(up[i][j-1],down[i][j-1])))+a[i][j];
        for(int i=1;i<=n;i++)  up[i][j]=max(up[i][j],max(up[i-1][j],max(up[i][j-1],down[i][j-1])))+a[i][j];
    }
    /*for(int i=1;i<=n;i++){
