            cout<<up[i][j]<<" ";
        }
        cout<<"\n";
    }
    cout<<"\n\n";
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cout<<down[i][j]<<" ";
        }
        cout<<"\n";
    }*/
    cout<<up[n][m];
    return 0;
}
